select count(*) from postgres.comments as c, postgres.posthistory as ph, postgres.badges as b, postgres.users as u where u.id = c.userid and u.id = ph.userid and u.id = b.userid and c.score=0 and c.creationdate>=timestamp '2010-09-05 16:04:35' and c.creationdate<=timestamp '2014-09-11 04:35:36' and ph.posthistorytypeid=1 and ph.creationdate>=timestamp '2010-07-26 20:01:58' and ph.creationdate<=timestamp '2014-09-13 17:29:23' and b."date"<=timestamp '2014-09-04 08:54:56';
